DO $$
DECLARE affected integer;
BEGIN
  IF (SELECT COUNT(*) FROM _adg_metadata_target_salon) <> 1 THEN
    RAISE EXCEPTION 'Expected exactly one active pinned asiandeligo channel';
  END IF;
  IF to_regclass('public.asiandeligo_catalog_metadata_batch5_product_backup_20260722') IS NULL
     OR to_regclass('public.asiandeligo_catalog_metadata_batch5_audit_20260722') IS NULL THEN
    RAISE EXCEPTION 'Required batch backup/audit table is missing';
  END IF;
  IF (
    SELECT COUNT(*)
    FROM public.asiandeligo_catalog_metadata_batch5_product_backup_20260722
    WHERE batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
      AND decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
      AND salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
  ) <> 18 THEN
    RAISE EXCEPTION 'Expected exactly 18 tenant- and decision-scoped backup rows';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.asiandeligo_catalog_metadata_batch5_audit_20260722
    WHERE batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
      AND decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
      AND salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
      AND action = 'backup_captured'
      AND product_rows = 18
  ) OR NOT EXISTS (
    SELECT 1 FROM public.asiandeligo_catalog_metadata_batch5_audit_20260722
    WHERE batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
      AND decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
      AND salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
      AND action = 'apply_complete'
      AND product_rows = 18
  ) OR EXISTS (
    SELECT 1 FROM public.asiandeligo_catalog_metadata_batch5_audit_20260722
    WHERE batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
      AND decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
      AND salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
      AND action = 'rollback_complete'
  ) THEN
    RAISE EXCEPTION 'Required apply audit chain is incomplete or rollback already completed';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM pg_catalog.pg_trigger
    WHERE tgrelid = 'public.products'::regclass
      AND tgname = 'zz_enforce_products_monotonic_updated_at'
      AND NOT tgisinternal
      AND tgenabled <> 'D'
  ) OR EXISTS (
    SELECT 1
    FROM _adg_metadata_decisions decision
    CROSS JOIN _adg_metadata_target_salon tenant
    LEFT JOIN public.asiandeligo_catalog_metadata_batch5_product_backup_20260722 backup
      ON backup.batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
     AND backup.decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
     AND backup.salon_id = tenant.salon_id
     AND backup.sku = decision.sku
     AND backup.product_id = decision.product_id
    AND backup.variant_id = decision.variant_id
    AND backup.category_id = decision.category_id
    AND backup.changed_fields = decision.changed_fields
    AND backup.original_updated_at = decision.expected_updated_at
    AND backup.applied_updated_at IS NOT NULL
    AND backup.applied_updated_at > backup.original_updated_at
    AND backup.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND backup.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND backup.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND backup.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND backup.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND backup.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND backup.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND backup.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure
    WHERE backup.sku IS NULL
  ) THEN
    RAISE EXCEPTION 'Required timestamp trigger or exact reviewed backup snapshot is missing';
  END IF;

  PERFORM 1
  FROM _adg_metadata_decisions decision
  CROSS JOIN _adg_metadata_target_salon tenant
  JOIN public.asiandeligo_catalog_metadata_batch5_product_backup_20260722 backup
    ON backup.batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
   AND backup.decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
   AND backup.salon_id = tenant.salon_id
   AND backup.sku = decision.sku
   AND backup.product_id = decision.product_id
    AND backup.variant_id = decision.variant_id
    AND backup.category_id = decision.category_id
    AND backup.changed_fields = decision.changed_fields
    AND backup.original_updated_at = decision.expected_updated_at
    AND backup.applied_updated_at IS NOT NULL
    AND backup.applied_updated_at > backup.original_updated_at
    AND backup.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND backup.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND backup.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND backup.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND backup.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND backup.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND backup.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND backup.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure
  JOIN public.product_variants variant
    ON variant.id = decision.variant_id
    AND variant.sku = decision.sku
    AND variant.salon_id = tenant.salon_id
   AND variant.is_active = TRUE
   AND variant.is_published = FALSE
   AND variant.is_for_sale = TRUE
   AND variant.sync_status = 'synced'
   AND variant.availability_status = 'IN_STOCK'
    AND variant.deleted_at IS NULL
  JOIN public.products product
    ON product.id = decision.product_id
    AND product.id = variant.template_id
    AND product.salon_id = tenant.salon_id
   AND product.name = decision.expected_name
   AND product.slug = decision.expected_slug
    AND product.updated_at = backup.applied_updated_at
   AND product.is_active = TRUE
   AND product.is_published = TRUE
   AND product.is_visible = TRUE
   AND product.status = 'active'
    AND product.deleted_at IS NULL
  JOIN public.categories category
    ON category.id = decision.category_id
   AND category.id = product.category_id
   AND category.salon_id = tenant.salon_id
   AND category.name = decision.category_name
   AND category.slug = decision.category_slug
   AND category.is_active = TRUE
  WHERE product.allergens IS NOT DISTINCT FROM decision.target_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.target_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.target_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.target_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.target_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.target_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure
  ORDER BY product.id
  FOR UPDATE OF product, variant, category;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 18 THEN
    RAISE EXCEPTION 'Expected 18 exact target row locks; refusing to overwrite intervening edits';
  END IF;
END $$;

DO $$
DECLARE affected integer;
BEGIN
  UPDATE public.products product
  SET allergens = backup.allergens,
      may_contain_allergens = backup.may_contain_allergens,
      storage_zone = backup.storage_zone,
      nutrition_facts = backup.nutrition_facts,
      country_of_origin = backup.country_of_origin,
      ingredients = backup.ingredients
  FROM _adg_metadata_decisions decision,
       _adg_metadata_target_salon tenant,
       public.asiandeligo_catalog_metadata_batch5_product_backup_20260722 backup
  WHERE backup.batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
    AND backup.decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
    AND backup.salon_id = tenant.salon_id
    AND backup.sku = decision.sku
    AND backup.product_id = product.id
    AND product.salon_id = tenant.salon_id
    AND product.name = decision.expected_name
    AND product.slug = decision.expected_slug
    AND product.updated_at = backup.applied_updated_at
    AND product.is_active = TRUE
    AND product.is_published = TRUE
    AND product.is_visible = TRUE
    AND product.status = 'active'
    AND product.deleted_at IS NULL
    AND backup.product_id = decision.product_id
    AND backup.variant_id = decision.variant_id
    AND backup.category_id = decision.category_id
    AND backup.changed_fields = decision.changed_fields
    AND backup.original_updated_at = decision.expected_updated_at
    AND backup.applied_updated_at IS NOT NULL
    AND backup.applied_updated_at > backup.original_updated_at
    AND backup.allergens IS NOT DISTINCT FROM decision.expected_allergens
    AND backup.may_contain_allergens IS NOT DISTINCT FROM decision.expected_may_contain_allergens
    AND backup.storage_zone IS NOT DISTINCT FROM decision.expected_storage_zone
    AND backup.nutrition_facts IS NOT DISTINCT FROM decision.expected_nutrition_facts
    AND backup.country_of_origin IS NOT DISTINCT FROM decision.expected_country_of_origin
    AND backup.ingredients IS NOT DISTINCT FROM decision.expected_ingredients
    AND backup.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND backup.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure
    AND product.allergens IS NOT DISTINCT FROM decision.target_allergens
    AND product.may_contain_allergens IS NOT DISTINCT FROM decision.target_may_contain_allergens
    AND product.storage_zone IS NOT DISTINCT FROM decision.target_storage_zone
    AND product.nutrition_facts IS NOT DISTINCT FROM decision.target_nutrition_facts
    AND product.country_of_origin IS NOT DISTINCT FROM decision.target_country_of_origin
    AND product.ingredients IS NOT DISTINCT FROM decision.target_ingredients
    AND product.price_per_unit IS NOT DISTINCT FROM decision.expected_price_per_unit
    AND product.unit_of_measure IS NOT DISTINCT FROM decision.expected_unit_of_measure;
  GET DIAGNOSTICS affected = ROW_COUNT;
  IF affected <> 18 THEN
    RAISE EXCEPTION 'Expected 18 exact product restorations, got %', affected;
  END IF;

  IF (
    SELECT COUNT(*)
    FROM public.products product
    JOIN public.asiandeligo_catalog_metadata_batch5_product_backup_20260722 backup
      ON backup.product_id = product.id
     AND backup.batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
     AND backup.decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
     AND backup.salon_id = product.salon_id
    WHERE product.salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
      AND product.updated_at > backup.applied_updated_at
      AND product.allergens IS NOT DISTINCT FROM backup.allergens
      AND product.may_contain_allergens IS NOT DISTINCT FROM backup.may_contain_allergens
      AND product.storage_zone IS NOT DISTINCT FROM backup.storage_zone
      AND product.nutrition_facts IS NOT DISTINCT FROM backup.nutrition_facts
      AND product.country_of_origin IS NOT DISTINCT FROM backup.country_of_origin
      AND product.ingredients IS NOT DISTINCT FROM backup.ingredients
      AND product.price_per_unit IS NOT DISTINCT FROM backup.price_per_unit
      AND product.unit_of_measure IS NOT DISTINCT FROM backup.unit_of_measure
  ) <> 18 THEN
    RAISE EXCEPTION 'Rollback post-state verification failed';
  END IF;

  INSERT INTO public.asiandeligo_catalog_metadata_batch5_audit_20260722 (
    batch_key, decision_sha256, channel_slug, salon_id, action, product_rows
  )
  SELECT 'asiandeligo-catalog-metadata-batch5-20260722-v1', '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f', channel_slug, salon_id,
         'rollback_complete', 18
  FROM _adg_metadata_target_salon;
END $$;

SELECT backup.sku, backup.changed_fields, audit.recorded_at, audit.transaction_id
FROM public.asiandeligo_catalog_metadata_batch5_product_backup_20260722 backup
JOIN public.asiandeligo_catalog_metadata_batch5_audit_20260722 audit
  ON audit.batch_key = backup.batch_key
 AND audit.salon_id = backup.salon_id
 AND audit.action = 'rollback_complete'
WHERE backup.batch_key = 'asiandeligo-catalog-metadata-batch5-20260722-v1'
  AND backup.decision_sha256 = '286cb02a38bd432f1d1f03d0594ddbe3a448dba69280cc36bc9d9d4dcc899b3f'
  AND backup.salon_id = 'e73271a9-53e3-4a20-a02e-791726b452aa'::uuid
ORDER BY backup.sku;

COMMIT;
